/**
 * Analytics route handlers — connects HTTP-like requests to AnalyticsService.
 *
 * These handlers parse and validate incoming request parameters, delegate to
 * the AnalyticsService, and return structured responses. They are framework-
 * agnostic: each handler takes a typed request object and returns a typed
 * response object that any HTTP layer can serialize.
 *
 * Depends on:
 * - AnalyticsService (service layer) for all analytics computation
 */

import type { AnalyticsService } from '../services/analytics.service.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricSummary,
  MetricType,
  OrderStatusBreakdown,
  TimeGranularity,
  TimeSeriesPoint,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

// ─── Request / Response types ───

export interface RouteResponse<T = unknown> {
  status: number;
  body: T | { error: string };
}

export interface DashboardRequest {
  startDate?: string;
  endDate?: string;
  granularity?: string;
  userId?: string;
}

export interface MetricRequest {
  metric?: string;
  startDate?: string;
  endDate?: string;
  granularity?: string;
  userId?: string;
}

export interface TimeSeriesRequest {
  metric?: string;
  startDate?: string;
  endDate?: string;
  granularity?: string;
  userId?: string;
}

export interface OrderStatusRequest {
  startDate?: string;
  endDate?: string;
  granularity?: string;
  userId?: string;
}

// ─── Serialized response types (Dates as ISO strings) ───

export interface SerializedTimeSeriesPoint {
  timestamp: string;
  value: number;
  label: string;
}

export interface SerializedMetricSummary {
  metric: MetricType;
  currentValue: number;
  previousValue: number;
  changePercent: number;
  trend: 'up' | 'down' | 'flat';
  timeSeries: SerializedTimeSeriesPoint[];
}

export interface SerializedDashboardData {
  summaries: SerializedMetricSummary[];
  ordersByStatus: OrderStatusBreakdown[];
  generatedAt: string;
  query: {
    startDate: string;
    endDate: string;
    granularity: TimeGranularity;
    userId?: string;
  };
}

// ─── Validation helpers ───

const VALID_METRICS: MetricType[] = [
  'total-orders',
  'total-revenue',
  'active-users',
  'order-completion-rate',
];

const VALID_GRANULARITIES: TimeGranularity[] = ['hour', 'day', 'week', 'month'];

function isValidMetric(value: string): value is MetricType {
  return VALID_METRICS.includes(value as MetricType);
}

function isValidGranularity(value: string): value is TimeGranularity {
  return VALID_GRANULARITIES.includes(value as TimeGranularity);
}

function parseDate(value: string): Date | null {
  const date = new Date(value);
  if (isNaN(date.getTime())) {
    return null;
  }
  return date;
}

function validateDateRange(
  startStr: string | undefined,
  endStr: string | undefined,
): { startDate: Date; endDate: Date } | { error: string } {
  if (!startStr) {
    return { error: 'Missing required parameter: startDate' };
  }
  if (!endStr) {
    return { error: 'Missing required parameter: endDate' };
  }

  const startDate = parseDate(startStr);
  if (!startDate) {
    return { error: `Invalid startDate: ${startStr}` };
  }

  const endDate = parseDate(endStr);
  if (!endDate) {
    return { error: `Invalid endDate: ${endStr}` };
  }

  if (startDate > endDate) {
    return { error: 'startDate must be before or equal to endDate' };
  }

  return { startDate, endDate };
}

function validateGranularity(
  value: string | undefined,
): TimeGranularity | { error: string } {
  if (!value) {
    return { error: 'Missing required parameter: granularity' };
  }
  if (!isValidGranularity(value)) {
    return { error: `Invalid granularity: ${value}. Must be one of: ${VALID_GRANULARITIES.join(', ')}` };
  }
  return value;
}

function buildQuery(params: {
  startDate?: string;
  endDate?: string;
  granularity?: string;
  userId?: string;
}): AnalyticsQuery | { error: string } {
  const dateResult = validateDateRange(params.startDate, params.endDate);
  if ('error' in dateResult) {
    return dateResult;
  }

  const granResult = validateGranularity(params.granularity);
  if (typeof granResult === 'object' && 'error' in granResult) {
    return granResult;
  }

  const query: AnalyticsQuery = {
    startDate: dateResult.startDate,
    endDate: dateResult.endDate,
    granularity: granResult,
  };

  if (params.userId) {
    query.userId = params.userId;
  }

  return query;
}

// ─── Serialization helpers ───

function serializeTimeSeriesPoint(point: TimeSeriesPoint): SerializedTimeSeriesPoint {
  return {
    timestamp: point.timestamp.toISOString(),
    value: point.value,
    label: point.label,
  };
}

function serializeMetricSummary(summary: MetricSummary): SerializedMetricSummary {
  return {
    metric: summary.metric,
    currentValue: summary.currentValue,
    previousValue: summary.previousValue,
    changePercent: summary.changePercent,
    trend: summary.trend,
    timeSeries: summary.timeSeries.map(serializeTimeSeriesPoint),
  };
}

function serializeDashboard(dashboard: DashboardData): SerializedDashboardData {
  return {
    summaries: dashboard.summaries.map(serializeMetricSummary),
    ordersByStatus: dashboard.ordersByStatus,
    generatedAt: dashboard.generatedAt.toISOString(),
    query: {
      startDate: dashboard.query.startDate.toISOString(),
      endDate: dashboard.query.endDate.toISOString(),
      granularity: dashboard.query.granularity,
      ...(dashboard.query.userId ? { userId: dashboard.query.userId } : {}),
    },
  };
}

// ─── Route handler class ───

export class AnalyticsRouteHandler {
  private logger = new Logger('AnalyticsRouteHandler');

  constructor(private analyticsService: AnalyticsService) {}

  /**
   * GET /analytics/dashboard
   * Returns the full dashboard with all metrics and order status breakdown.
   */
  getDashboard(params: DashboardRequest): RouteResponse<SerializedDashboardData> {
    const queryResult = buildQuery(params);
    if ('error' in queryResult) {
      return { status: 400, body: { error: queryResult.error } };
    }

    try {
      const dashboard = this.analyticsService.getDashboard(queryResult);
      return { status: 200, body: serializeDashboard(dashboard) };
    } catch (err) {
      this.logger.error(`Failed to get dashboard: ${err}`);
      return { status: 500, body: { error: 'Internal server error' } };
    }
  }

  /**
   * GET /analytics/metrics/:metric
   * Returns a single metric summary with trend and time series.
   */
  getMetric(params: MetricRequest): RouteResponse<SerializedMetricSummary> {
    if (!params.metric) {
      return { status: 400, body: { error: 'Missing required parameter: metric' } };
    }
    if (!isValidMetric(params.metric)) {
      return {
        status: 400,
        body: { error: `Invalid metric: ${params.metric}. Must be one of: ${VALID_METRICS.join(', ')}` },
      };
    }

    const queryResult = buildQuery(params);
    if ('error' in queryResult) {
      return { status: 400, body: { error: queryResult.error } };
    }

    try {
      const summary = this.analyticsService.getMetricSummary(params.metric, queryResult);
      return { status: 200, body: serializeMetricSummary(summary) };
    } catch (err) {
      this.logger.error(`Failed to get metric ${params.metric}: ${err}`);
      return { status: 500, body: { error: 'Internal server error' } };
    }
  }

  /**
   * GET /analytics/time-series/:metric
   * Returns raw time-series data for a specific metric.
   */
  getTimeSeries(params: TimeSeriesRequest): RouteResponse<SerializedTimeSeriesPoint[]> {
    if (!params.metric) {
      return { status: 400, body: { error: 'Missing required parameter: metric' } };
    }
    if (!isValidMetric(params.metric)) {
      return {
        status: 400,
        body: { error: `Invalid metric: ${params.metric}. Must be one of: ${VALID_METRICS.join(', ')}` },
      };
    }

    const queryResult = buildQuery(params);
    if ('error' in queryResult) {
      return { status: 400, body: { error: queryResult.error } };
    }

    try {
      const series = this.analyticsService.getTimeSeries(params.metric, queryResult);
      return { status: 200, body: series.map(serializeTimeSeriesPoint) };
    } catch (err) {
      this.logger.error(`Failed to get time series for ${params.metric}: ${err}`);
      return { status: 500, body: { error: 'Internal server error' } };
    }
  }

  /**
   * GET /analytics/order-status
   * Returns order count breakdown by status.
   */
  getOrderStatus(params: OrderStatusRequest): RouteResponse<OrderStatusBreakdown[]> {
    const queryResult = buildQuery(params);
    if ('error' in queryResult) {
      return { status: 400, body: { error: queryResult.error } };
    }

    try {
      const breakdown = this.analyticsService.getOrderStatusBreakdown(queryResult);
      return { status: 200, body: breakdown };
    } catch (err) {
      this.logger.error(`Failed to get order status breakdown: ${err}`);
      return { status: 500, body: { error: 'Internal server error' } };
    }
  }
}

