import { describe, it, expect, beforeEach } from 'vitest';
import { Database, resetDatabase } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { AnalyticsRouteHandler } from '../../src/routes/analytics.routes.js';
import type { Order } from '../../src/models/order.js';

function makeOrder(
  repo: OrderRepository,
  overrides: Partial<Order> & { id: string; userId: string },
): Order {
  const order: Order = {
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 10,
    status: 'pending',
    createdAt: new Date('2024-01-15'),
    updatedAt: new Date('2024-01-15'),
    ...overrides,
  };
  repo.save(order);
  return order;
}

describe('AnalyticsRouteHandler', () => {
  let orderRepo: OrderRepository;
  let handler: AnalyticsRouteHandler;

  beforeEach(() => {
    resetDatabase();
    const db = new Database();
    const userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    const service = new AnalyticsService(orderRepo, userRepo);
    handler = new AnalyticsRouteHandler(service);
  });

  // ─── getDashboard ───

  describe('getDashboard', () => {
    it('should return 200 with full dashboard data', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', total: 50, status: 'delivered', createdAt: new Date('2024-01-15') });

      const response = handler.getDashboard({
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(200);
      const body = response.body as any;
      expect(body.summaries).toHaveLength(4);
      expect(body.summaries.map((s: any) => s.metric).sort()).toEqual([
        'active-users',
        'order-completion-rate',
        'total-orders',
        'total-revenue',
      ]);
      expect(body.ordersByStatus).toHaveLength(1);
      expect(body.generatedAt).toBeDefined();
      expect(typeof body.generatedAt).toBe('string');
      expect(body.query.startDate).toBe('2024-01-01T00:00:00.000Z');
      expect(body.query.granularity).toBe('day');
    });

    it('should serialize dates as ISO strings', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', createdAt: new Date('2024-01-15') });

      const response = handler.getDashboard({
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(200);
      const body = response.body as any;
      // All timestamps in time series should be ISO strings
      for (const summary of body.summaries) {
        for (const point of summary.timeSeries) {
          expect(typeof point.timestamp).toBe('string');
        }
      }
    });

    it('should pass userId filter when provided', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', total: 100, createdAt: new Date('2024-01-15') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u2', total: 200, createdAt: new Date('2024-01-16') });

      const response = handler.getDashboard({
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
        userId: 'u1',
      });

      expect(response.status).toBe(200);
      const body = response.body as any;
      const revenue = body.summaries.find((s: any) => s.metric === 'total-revenue');
      expect(revenue.currentValue).toBe(100);
      expect(body.query.userId).toBe('u1');
    });

    it('should return 400 when startDate is missing', () => {
      const response = handler.getDashboard({
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(400);
      expect((response.body as any).error).toMatch(/startDate/);
    });

    it('should return 400 when endDate is missing', () => {
      const response = handler.getDashboard({
        startDate: '2024-01-01',
        granularity: 'day',
      });

      expect(response.status).toBe(400);
      expect((response.body as any).error).toMatch(/endDate/);
    });

    it('should return 400 when granularity is missing', () => {
      const response = handler.getDashboard({
        startDate: '2024-01-01',
        endDate: '2024-01-31',
      });

      expect(response.status).toBe(400);
      expect((response.body as any).error).toMatch(/granularity/);
    });

    it('should return 400 for invalid granularity', () => {
      const response = handler.getDashboard({
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'quarter',
      });

      expect(response.status).toBe(400);
      expect((response.body as any).error).toMatch(/Invalid granularity/);
    });

    it('should return 400 for invalid date format', () => {
      const response = handler.getDashboard({
        startDate: 'not-a-date',
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(400);
      expect((response.body as any).error).toMatch(/Invalid startDate/);
    });

    it('should return 400 when startDate is after endDate', () => {
      const response = handler.getDashboard({
        startDate: '2024-02-01',
        endDate: '2024-01-01',
        granularity: 'day',
      });

      expect(response.status).toBe(400);
      expect((response.body as any).error).toMatch(/startDate must be before/);
    });
  });

  // ─── getMetric ───

  describe('getMetric', () => {
    it('should return 200 with metric summary for valid request', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', total: 50, createdAt: new Date('2024-01-15') });

      const response = handler.getMetric({
        metric: 'total-revenue',
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(200);
      const body = response.body as any;
      expect(body.metric).toBe('total-revenue');
      expect(body.currentValue).toBe(50);
      expect(body.trend).toBeDefined();
      expect(body.timeSeries).toBeInstanceOf(Array);
    });

    it('should return 400 when metric is missing', () => {
      const response = handler.getMetric({
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(400);
      expect((response.body as any).error).toMatch(/metric/);
    });

    it('should return 400 for invalid metric type', () => {
      const response = handler.getMetric({
        metric: 'invalid-metric',
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(400);
      expect((response.body as any).error).toMatch(/Invalid metric/);
    });

    it('should return all four metric types correctly', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', total: 100, status: 'delivered', createdAt: new Date('2024-01-15') });

      for (const metric of ['total-orders', 'total-revenue', 'active-users', 'order-completion-rate']) {
        const response = handler.getMetric({
          metric,
          startDate: '2024-01-01',
          endDate: '2024-01-31',
          granularity: 'day',
        });
        expect(response.status).toBe(200);
        expect((response.body as any).metric).toBe(metric);
      }
    });

    it('should include trend information', () => {
      // Previous period: Dec 1-31
      makeOrder(orderRepo, { id: 'o-prev', userId: 'u1', createdAt: new Date('2023-12-15') });
      // Current period: Jan 1-31
      makeOrder(orderRepo, { id: 'o-cur1', userId: 'u1', createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o-cur2', userId: 'u1', createdAt: new Date('2024-01-20') });

      const response = handler.getMetric({
        metric: 'total-orders',
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(200);
      const body = response.body as any;
      expect(body.currentValue).toBe(2);
      expect(body.previousValue).toBe(1);
      expect(body.changePercent).toBe(100);
      expect(body.trend).toBe('up');
    });
  });

  // ─── getTimeSeries ───

  describe('getTimeSeries', () => {
    it('should return 200 with time series data', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', createdAt: new Date('2024-01-02T10:00:00Z') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', createdAt: new Date('2024-01-02T14:00:00Z') });

      const response = handler.getTimeSeries({
        metric: 'total-orders',
        startDate: '2024-01-01',
        endDate: '2024-01-04',
        granularity: 'day',
      });

      expect(response.status).toBe(200);
      const body = response.body as any[];
      expect(body.length).toBe(3);
      // Each point should have serialized timestamp
      for (const point of body) {
        expect(typeof point.timestamp).toBe('string');
        expect(typeof point.value).toBe('number');
        expect(typeof point.label).toBe('string');
      }
    });

    it('should return 400 when metric is missing', () => {
      const response = handler.getTimeSeries({
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(400);
      expect((response.body as any).error).toMatch(/metric/);
    });

    it('should return 400 for invalid metric', () => {
      const response = handler.getTimeSeries({
        metric: 'bad-metric',
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(400);
      expect((response.body as any).error).toMatch(/Invalid metric/);
    });

    it('should return empty array for zero-duration range', () => {
      const response = handler.getTimeSeries({
        metric: 'total-orders',
        startDate: '2024-01-01',
        endDate: '2024-01-01',
        granularity: 'day',
      });

      expect(response.status).toBe(200);
      expect(response.body).toEqual([]);
    });
  });

  // ─── getOrderStatus ───

  describe('getOrderStatus', () => {
    it('should return 200 with order status breakdown', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', status: 'pending', createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u1', status: 'pending', createdAt: new Date('2024-01-11') });
      makeOrder(orderRepo, { id: 'o3', userId: 'u1', status: 'delivered', createdAt: new Date('2024-01-12') });

      const response = handler.getOrderStatus({
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(200);
      const body = response.body as any[];
      expect(body.length).toBe(2);

      const pending = body.find((b: any) => b.status === 'pending');
      expect(pending.count).toBe(2);
      expect(pending.percent).toBeCloseTo(66.67, 1);

      const delivered = body.find((b: any) => b.status === 'delivered');
      expect(delivered.count).toBe(1);
      expect(delivered.percent).toBeCloseTo(33.33, 1);
    });

    it('should return empty array when no orders exist', () => {
      const response = handler.getOrderStatus({
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
      });

      expect(response.status).toBe(200);
      expect(response.body).toEqual([]);
    });

    it('should return 400 for missing parameters', () => {
      const response = handler.getOrderStatus({});

      expect(response.status).toBe(400);
      expect((response.body as any).error).toBeDefined();
    });

    it('should filter by userId', () => {
      makeOrder(orderRepo, { id: 'o1', userId: 'u1', status: 'pending', createdAt: new Date('2024-01-10') });
      makeOrder(orderRepo, { id: 'o2', userId: 'u2', status: 'delivered', createdAt: new Date('2024-01-11') });

      const response = handler.getOrderStatus({
        startDate: '2024-01-01',
        endDate: '2024-01-31',
        granularity: 'day',
        userId: 'u1',
      });

      expect(response.status).toBe(200);
      const body = response.body as any[];
      expect(body.length).toBe(1);
      expect(body[0].status).toBe('pending');
    });
  });
});

